CREATE TABLE photos (
    id          TEXT PRIMARY KEY,
    timestamp   TEXT NOT NULL,
    sender_id   TEXT NOT NULL,
    filename    TEXT NOT NULL,
    orig_name   TEXT DEFAULT '',
    size_bytes  INTEGER DEFAULT 0,
    annotation  TEXT DEFAULT '',
    analysis    TEXT DEFAULT '',
    tags        TEXT DEFAULT '',
    source      TEXT DEFAULT 'qqbot'
);
CREATE INDEX idx_photos_sender ON photos(sender_id);
CREATE INDEX idx_photos_time ON photos(timestamp DESC);
CREATE INDEX idx_photos_tags ON photos(tags);
CREATE INDEX idx_sender_time ON photos(sender_id, timestamp DESC);

